export const RELAY_SCHEMA_VERSION = 1;

export const DEFAULT_COLUMNS: RelayColumn[] = [
  { id: "todo", name: "Todo", position: 1000, terminal: false },
  { id: "in_progress", name: "In Progress", position: 2000, terminal: false },
  { id: "needs_clarification", name: "Needs Clarification", position: 3000, terminal: false },
  { id: "not_doing", name: "Not Doing", position: 4000, terminal: true },
  { id: "completed", name: "Completed", position: 5000, terminal: true }
];

export type TicketPriority = "low" | "medium" | "high" | "urgent";
export type RunStatus = "idle" | "drafting" | "running" | "blocked" | "failed" | "completed" | "cancelled";
export type ProjectHealth = "ok" | "warning" | "error";
export type ThemePreference = "system" | "light" | "dark";

export type RelayColumn = {
  id: string;
  name: string;
  position: number;
  terminal: boolean;
};

export type ProjectSettings = {
  defaultModel: string | null;
  defaultApprovalPolicy: "untrusted" | "on-request" | "never";
  defaultSandboxMode: "read-only" | "workspace-write" | "danger-full-access";
  allowNonGitCodexRuns: boolean;
  ticketDraftingEnabled: boolean;
  codexExecutionEnabled: boolean;
};

export type ProjectConfig = {
  schemaVersion: number;
  projectId: string;
  name: string;
  createdAt: string;
  updatedAt: string;
  columns: RelayColumn[];
  settings: ProjectSettings;
};

export type ProjectSummary = {
  projectId: string | null;
  name: string;
  path: string;
  exists: boolean;
  isGitRepository: boolean;
  relayInitialized: boolean;
  health: ProjectHealth;
  healthMessages: string[];
  activeRunCount: number;
  lastOpenedAt?: string;
};

export type TicketFrontMatter = {
  schemaVersion: number;
  id: string;
  title: string;
  status: string;
  position: number;
  priority: TicketPriority;
  labels: string[];
  createdAt: string;
  updatedAt: string;
  codexThreadId: string | null;
  runStatus: RunStatus;
  lastRunId: string | null;
};

export type TicketRecord = {
  frontMatter: TicketFrontMatter;
  markdown: string;
  filePath: string;
};

export type TicketSummary = TicketFrontMatter & {
  excerpt: string;
  filePath: string;
};

export type InvalidTicket = {
  filePath: string;
  reason: string;
};

export type BoardSnapshot = {
  project: ProjectSummary;
  config: ProjectConfig | null;
  columns: RelayColumn[];
  tickets: TicketSummary[];
  invalidTickets: InvalidTicket[];
};

export type TicketDraft = {
  title: string;
  priority: TicketPriority;
  labels: string[];
  context: string;
  requirements: string[];
  acceptanceCriteria: string[];
  clarificationQuestions: string[];
  implementationNotes: string[];
};

export type TicketCreateInput = {
  title: string;
  priority: TicketPriority;
  labels: string[];
  markdown: string;
  status?: string;
};

export type TicketSaveInput = {
  projectPath: string;
  ticket: TicketRecord;
};

export type TicketMoveInput = {
  projectPath: string;
  ticketId: string;
  targetStatus: string;
  beforeTicketId?: string | null;
  afterTicketId?: string | null;
};

export type AddProjectResult = {
  project: ProjectSummary;
  initialized: boolean;
};

export type AppRegistry = {
  schemaVersion: number;
  projects: Array<{
    path: string;
    pinned: boolean;
    lastOpenedAt: string;
    sidebarPosition: number;
  }>;
  ui: {
    lastProjectPath: string | null;
    theme: ThemePreference;
  };
};

export type RelayCodexEvent =
  | { type: "run.started"; runId: string; threadId: string; timestamp: string }
  | { type: "agent.message.delta"; text: string; timestamp: string }
  | { type: "agent.message.completed"; text: string; timestamp: string }
  | { type: "command.started"; command: string; cwd?: string; timestamp: string }
  | { type: "command.output"; stream: "stdout" | "stderr"; text: string; timestamp: string }
  | { type: "command.completed"; status: "completed" | "failed" | "declined"; timestamp: string }
  | { type: "file.change"; path: string; summary?: string; timestamp: string }
  | { type: "approval.requested"; approvalId: string; kind: "command" | "file-change" | "network" | "other"; payload: unknown; timestamp: string }
  | { type: "approval.resolved"; approvalId: string; decision: string; timestamp: string }
  | { type: "run.completed"; finalResponse: string; usage?: unknown; timestamp: string }
  | { type: "run.failed"; message: string; details?: unknown; timestamp: string };

export type RendererRunEvent = RelayCodexEvent & {
  projectPath: string;
  ticketId: string;
  runId: string;
};

export type RelayApprovalDecision = "accept" | "acceptForSession" | "decline" | "cancel";

export type CodexStatus = {
  sdkAvailable: boolean;
  cliAvailable: boolean;
  cliVersion: string | null;
  authenticated: boolean | null;
  message: string;
};

export type StartRunInput = {
  projectPath: string;
  ticketId: string;
  freshThread?: boolean;
};

export type CreateDraftInput = {
  projectPath: string;
  idea: string;
};

export type RunLogLine = {
  schemaVersion: number;
  timestamp: string;
  ticketId: string;
  runId: string;
  threadId: string;
  type: RelayCodexEvent["type"];
  payload: Record<string, unknown>;
};

export type RelayApi = {
  projects: {
    list: () => Promise<ProjectSummary[]>;
    addFolder: () => Promise<AddProjectResult | null>;
    removeFromSidebar: (projectPath: string) => Promise<ProjectSummary[]>;
    read: (projectPath: string) => Promise<ProjectSummary>;
    revealInFinder: (projectPath: string) => Promise<void>;
  };
  board: {
    read: (projectPath: string) => Promise<BoardSnapshot>;
  };
  ticket: {
    createDraft: (input: CreateDraftInput) => Promise<TicketDraft>;
    createManual: (projectPath: string, input: TicketCreateInput) => Promise<TicketRecord>;
    read: (projectPath: string, ticketId: string) => Promise<TicketRecord>;
    save: (input: TicketSaveInput) => Promise<TicketRecord>;
    move: (input: TicketMoveInput) => Promise<BoardSnapshot>;
    delete: (projectPath: string, ticketId: string) => Promise<BoardSnapshot>;
    duplicate: (projectPath: string, ticketId: string) => Promise<TicketRecord>;
    revealFile: (projectPath: string, ticketId: string) => Promise<void>;
  };
  codex: {
    status: () => Promise<CodexStatus>;
    startRun: (input: StartRunInput) => Promise<{ runId: string; threadId: string }>;
    resumeRun: (input: StartRunInput) => Promise<{ runId: string; threadId: string }>;
    cancelRun: (runId: string) => Promise<void>;
    approveAction: (approvalId: string, decision: RelayApprovalDecision) => Promise<void>;
    onRunEvent: (listener: (event: RendererRunEvent) => void) => () => void;
  };
};

import { shell } from "electron";
import matter from "gray-matter";
import { access, mkdir, readdir, readFile, rename, stat, writeFile } from "node:fs/promises";
import path from "node:path";
import { ulid } from "ulid";
import {
  DEFAULT_COLUMNS,
  RELAY_SCHEMA_VERSION,
  type BoardSnapshot,
  type InvalidTicket,
  type ProjectConfig,
  type ProjectSettings,
  type ProjectSummary,
  type RelayColumn,
  type TicketCreateInput,
  type TicketDraft,
  type TicketFrontMatter,
  type TicketMoveInput,
  type TicketRecord,
  type TicketSummary
} from "../../shared/types";
import { projectConfigSchema, ticketFrontMatterSchema } from "./schemas";

const defaultSettings = (): ProjectSettings => ({
  defaultModel: null,
  defaultApprovalPolicy: "on-request",
  defaultSandboxMode: "workspace-write",
  allowNonGitCodexRuns: false,
  ticketDraftingEnabled: true,
  codexExecutionEnabled: true
});

const nowIso = (): string => new Date().toISOString();
const projectRelayPath = (projectPath: string): string => path.join(projectPath, ".relay");
const projectConfigPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "project.json");
const ticketsPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "tickets");
export const runsPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "runs");
const trashPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "trash");
const attachmentsPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "attachments");
const backupsPath = (projectPath: string): string => path.join(projectRelayPath(projectPath), "backups");

export const newId = (prefix: string): string => `${prefix}_${ulid().toLowerCase()}`;

const fileExists = async (target: string): Promise<boolean> => {
  try {
    await access(target);
    return true;
  } catch {
    return false;
  }
};

export const isGitRepository = async (projectPath: string): Promise<boolean> => fileExists(path.join(projectPath, ".git"));

const atomicWriteJson = async (target: string, value: unknown): Promise<void> => {
  await mkdir(path.dirname(target), { recursive: true });
  const tmp = `${target}.${process.pid}.tmp`;
  await writeFile(tmp, `${JSON.stringify(value, null, 2)}\n`, "utf8");
  await rename(tmp, target);
};

const atomicWriteText = async (target: string, value: string): Promise<void> => {
  await mkdir(path.dirname(target), { recursive: true });
  const tmp = `${target}.${process.pid}.tmp`;
  await writeFile(tmp, value, "utf8");
  await rename(tmp, target);
};

const assertDirectory = async (projectPath: string): Promise<void> => {
  const info = await stat(projectPath);
  if (!info.isDirectory()) {
    throw new Error(`Project path is not a directory: ${projectPath}`);
  }
};

export const isRelayInitialized = async (projectPath: string): Promise<boolean> => fileExists(projectConfigPath(projectPath));

export const initializeProject = async (projectPath: string): Promise<ProjectConfig> => {
  const resolved = path.resolve(projectPath);
  await assertDirectory(resolved);
  const existing = await isRelayInitialized(resolved);
  if (existing) return readProjectConfig(resolved);

  const now = nowIso();
  const config: ProjectConfig = {
    schemaVersion: RELAY_SCHEMA_VERSION,
    projectId: newId("prj"),
    name: path.basename(resolved),
    createdAt: now,
    updatedAt: now,
    columns: DEFAULT_COLUMNS.map((column) => ({ ...column })),
    settings: defaultSettings()
  };

  await mkdir(ticketsPath(resolved), { recursive: true });
  await mkdir(runsPath(resolved), { recursive: true });
  await mkdir(attachmentsPath(resolved), { recursive: true });
  await mkdir(backupsPath(resolved), { recursive: true });
  await atomicWriteJson(projectConfigPath(resolved), config);
  return config;
};

export const readProjectConfig = async (projectPath: string): Promise<ProjectConfig> => {
  const raw = await readFile(projectConfigPath(projectPath), "utf8");
  return projectConfigSchema.parse(JSON.parse(raw)) as ProjectConfig;
};

export const writeProjectConfig = async (projectPath: string, config: ProjectConfig): Promise<ProjectConfig> => {
  const updated = { ...config, updatedAt: nowIso() };
  await atomicWriteJson(projectConfigPath(projectPath), updated);
  return updated;
};

export const summarizeProject = async (projectPath: string, lastOpenedAt?: string): Promise<ProjectSummary> => {
  const resolved = path.resolve(projectPath);
  const exists = await fileExists(resolved);
  const healthMessages: string[] = [];
  let config: ProjectConfig | null = null;
  let relayInitialized = false;
  let activeRunCount = 0;

  if (!exists) {
    return {
      projectId: null,
      name: path.basename(resolved),
      path: resolved,
      exists: false,
      isGitRepository: false,
      relayInitialized: false,
      health: "error",
      healthMessages: ["Project folder is missing."],
      activeRunCount: 0,
      lastOpenedAt
    };
  }

  relayInitialized = await isRelayInitialized(resolved);
  const git = await isGitRepository(resolved);

  if (!relayInitialized) {
    healthMessages.push("Relay has not initialized this project yet.");
  } else {
    try {
      config = await readProjectConfig(resolved);
      const tickets = await readTickets(resolved, config.columns);
      activeRunCount = tickets.tickets.filter((ticket) => ticket.runStatus === "running" || ticket.runStatus === "blocked").length;
      if (tickets.invalidTickets.length > 0) {
        healthMessages.push(`${tickets.invalidTickets.length} ticket file(s) need attention.`);
      }
    } catch (error) {
      healthMessages.push(error instanceof Error ? error.message : "Project metadata is invalid.");
    }
  }

  if (!git) {
    healthMessages.push("This folder is not a Git repository. Codex execution is disabled by default.");
  }

  const hasError = exists && relayInitialized && !config;
  const health = hasError ? "error" : healthMessages.length > 0 ? "warning" : "ok";

  return {
    projectId: config?.projectId ?? null,
    name: config?.name ?? path.basename(resolved),
    path: resolved,
    exists,
    isGitRepository: git,
    relayInitialized,
    health,
    healthMessages,
    activeRunCount,
    lastOpenedAt
  };
};

const extractExcerpt = (markdown: string): string => {
  const text = markdown
    .replace(/^# .+$/m, "")
    .replace(/^## .+$/gm, "")
    .replace(/[-*]\s+/g, "")
    .replace(/\s+/g, " ")
    .trim();
  return text.length > 160 ? `${text.slice(0, 157)}...` : text;
};

const readTicketFile = async (filePath: string): Promise<TicketRecord> => {
  const raw = await readFile(filePath, "utf8");
  const parsed = matter(raw);
  const frontMatter = ticketFrontMatterSchema.parse(parsed.data) as TicketFrontMatter;
  return {
    frontMatter,
    markdown: parsed.content.trimStart(),
    filePath
  };
};

const readTickets = async (
  projectPath: string,
  columns: RelayColumn[]
): Promise<{ tickets: TicketSummary[]; records: TicketRecord[]; invalidTickets: InvalidTicket[] }> => {
  await mkdir(ticketsPath(projectPath), { recursive: true });
  const entries = await readdir(ticketsPath(projectPath), { withFileTypes: true });
  const validColumnIds = new Set(columns.map((column) => column.id));
  const tickets: TicketSummary[] = [];
  const records: TicketRecord[] = [];
  const invalidTickets: InvalidTicket[] = [];

  for (const entry of entries) {
    if (!entry.isFile() || !entry.name.endsWith(".md")) continue;
    const filePath = path.join(ticketsPath(projectPath), entry.name);
    try {
      const record = await readTicketFile(filePath);
      if (!validColumnIds.has(record.frontMatter.status)) {
        invalidTickets.push({ filePath, reason: `Unknown status: ${record.frontMatter.status}` });
        continue;
      }
      records.push(record);
      tickets.push({
        ...record.frontMatter,
        excerpt: extractExcerpt(record.markdown),
        filePath
      });
    } catch (error) {
      invalidTickets.push({
        filePath,
        reason: error instanceof Error ? error.message : "Unable to parse ticket."
      });
    }
  }

  tickets.sort((a, b) => {
    if (a.status !== b.status) return a.status.localeCompare(b.status);
    return a.position - b.position;
  });

  return { tickets, records, invalidTickets };
};

export const readBoard = async (projectPath: string, lastOpenedAt?: string): Promise<BoardSnapshot> => {
  const resolved = path.resolve(projectPath);
  const project = await summarizeProject(resolved, lastOpenedAt);

  if (!project.exists || !project.relayInitialized) {
    return {
      project,
      config: null,
      columns: DEFAULT_COLUMNS.map((column) => ({ ...column })),
      tickets: [],
      invalidTickets: []
    };
  }

  const config = await readProjectConfig(resolved);
  const { tickets, invalidTickets } = await readTickets(resolved, config.columns);
  return {
    project,
    config,
    columns: [...config.columns].sort((a, b) => a.position - b.position),
    tickets,
    invalidTickets
  };
};

const ticketPath = (projectPath: string, ticketId: string): string => path.join(ticketsPath(projectPath), `${ticketId}.md`);

export const readTicket = async (projectPath: string, ticketId: string): Promise<TicketRecord> => {
  return readTicketFile(ticketPath(projectPath, ticketId));
};

const stringifyTicket = (ticket: TicketRecord): string => {
  const body = ticket.markdown.trimStart();
  return matter.stringify(body.endsWith("\n") ? body : `${body}\n`, ticket.frontMatter);
};

export const writeTicket = async (projectPath: string, ticket: TicketRecord): Promise<TicketRecord> => {
  const target = ticketPath(projectPath, ticket.frontMatter.id);
  const next: TicketRecord = {
    ...ticket,
    filePath: target,
    frontMatter: {
      ...ticket.frontMatter,
      updatedAt: nowIso()
    }
  };
  await atomicWriteText(target, stringifyTicket(next));
  return next;
};

export const ticketMarkdownFromDraft = (draft: TicketDraft): string => {
  const list = (items: string[]): string => (items.length > 0 ? items.map((item) => `- ${item}`).join("\n") : "- None.");
  return `# ${draft.title}

## Context

${draft.context || "No additional context provided."}

## Requirements

${list(draft.requirements)}

## Acceptance Criteria

${list(draft.acceptanceCriteria)}

## Clarification Questions

${list(draft.clarificationQuestions)}

## Implementation Notes

${list(draft.implementationNotes)}

## Codex Handoff

No Codex run has been started.
`;
};

export const createTicket = async (projectPath: string, input: TicketCreateInput): Promise<TicketRecord> => {
  const config = await readProjectConfig(projectPath);
  const status = input.status ?? "todo";
  if (!config.columns.some((column) => column.id === status)) {
    throw new Error(`Unknown ticket status: ${status}`);
  }
  const board = await readBoard(projectPath);
  const lastPosition = Math.max(0, ...board.tickets.filter((ticket) => ticket.status === status).map((ticket) => ticket.position));
  const createdAt = nowIso();
  const frontMatter: TicketFrontMatter = {
    schemaVersion: RELAY_SCHEMA_VERSION,
    id: newId("tkt"),
    title: input.title.trim(),
    status,
    position: lastPosition + 1000,
    priority: input.priority,
    labels: input.labels.map((label) => label.trim()).filter(Boolean),
    createdAt,
    updatedAt: createdAt,
    codexThreadId: null,
    runStatus: "idle",
    lastRunId: null
  };
  const ticket: TicketRecord = {
    frontMatter,
    markdown: input.markdown,
    filePath: ticketPath(projectPath, frontMatter.id)
  };
  return writeTicket(projectPath, ticket);
};

const calculatePosition = (tickets: TicketSummary[], targetStatus: string, beforeId?: string | null, afterId?: string | null): number => {
  const targetTickets = tickets
    .filter((ticket) => ticket.status === targetStatus && ticket.id !== beforeId && ticket.id !== afterId)
    .sort((a, b) => a.position - b.position);
  const before = beforeId ? tickets.find((ticket) => ticket.id === beforeId) : null;
  const after = afterId ? tickets.find((ticket) => ticket.id === afterId) : null;

  if (before && after) return (before.position + after.position) / 2;
  if (before) return before.position - 1000;
  if (after) return after.position + 1000;
  return (targetTickets.at(-1)?.position ?? 0) + 1000;
};

export const moveTicket = async (input: TicketMoveInput): Promise<BoardSnapshot> => {
  const config = await readProjectConfig(input.projectPath);
  if (!config.columns.some((column) => column.id === input.targetStatus)) {
    throw new Error(`Unknown ticket status: ${input.targetStatus}`);
  }
  const board = await readBoard(input.projectPath);
  const record = await readTicket(input.projectPath, input.ticketId);
  const position = calculatePosition(board.tickets, input.targetStatus, input.beforeTicketId, input.afterTicketId);
  await writeTicket(input.projectPath, {
    ...record,
    frontMatter: {
      ...record.frontMatter,
      status: input.targetStatus,
      position
    }
  });
  return readBoard(input.projectPath);
};

export const deleteTicket = async (projectPath: string, ticketId: string): Promise<BoardSnapshot> => {
  const source = ticketPath(projectPath, ticketId);
  const stamp = new Date().toISOString().replace(/[:.]/g, "-");
  const target = path.join(trashPath(projectPath), stamp, `${ticketId}.md`);
  await mkdir(path.dirname(target), { recursive: true });
  await rename(source, target);
  return readBoard(projectPath);
};

export const duplicateTicket = async (projectPath: string, ticketId: string): Promise<TicketRecord> => {
  const source = await readTicket(projectPath, ticketId);
  return createTicket(projectPath, {
    title: `${source.frontMatter.title} Copy`,
    priority: source.frontMatter.priority,
    labels: source.frontMatter.labels,
    markdown: source.markdown,
    status: source.frontMatter.status
  });
};

export const revealTicketFile = async (projectPath: string, ticketId: string): Promise<void> => {
  shell.showItemInFolder(ticketPath(projectPath, ticketId));
};

export const appendCodexHandoff = (markdown: string, handoff: string): string => {
  const marker = "## Codex Handoff";
  const entry = `\n\n### ${new Date().toLocaleString()}\n\n${handoff.trim()}\n`;
  if (!markdown.includes(marker)) {
    return `${markdown.trimEnd()}\n\n${marker}${entry}`;
  }
  return markdown.replace(marker, `${marker}${entry}`);
};

import { BrowserWindow } from "electron";
import { appendFile, mkdir, readFile } from "node:fs/promises";
import os from "node:os";
import path from "node:path";
import { execFile } from "node:child_process";
import { promisify } from "node:util";
import { Codex, type Input, type Thread, type ThreadEvent, type ThreadItem, type ThreadOptions } from "@openai/codex-sdk";
import {
  type CodexStatus,
  type CreateDraftInput,
  type RelayCodexEvent,
  type RendererRunEvent,
  type StartRunInput,
  type TicketDraft
} from "../../shared/types";
import { ticketDraftSchema } from "./schemas";
import { logError, logInfo, logWarn } from "./logger";
import {
  appendCodexHandoff,
  isGitRepository,
  newId,
  readProjectConfig,
  readTicket,
  runsPath,
  ticketMarkdownFromDraft,
  writeTicket
} from "./storage";

const execFileAsync = promisify(execFile);
const DRAFT_TIMEOUT_MS = 90_000;

type ActiveRun = {
  abortController: AbortController;
  ticketId: string;
  projectPath: string;
};

const activeRuns = new Map<string, ActiveRun>();

const nowIso = (): string => new Date().toISOString();

const codexEnv = (): Record<string, string> => {
  const env: Record<string, string> = {};
  for (const [key, value] of Object.entries(process.env)) {
    if (typeof value === "string") env[key] = value;
  }
  return env;
};

const createCodex = (): Codex => new Codex({ env: codexEnv() });

const threadOptionsForProject = async (projectPath: string): Promise<ThreadOptions> => {
  const config = await readProjectConfig(projectPath);
  const git = await isGitRepository(projectPath);
  return {
    workingDirectory: projectPath,
    model: config.settings.defaultModel ?? undefined,
    approvalPolicy: config.settings.defaultApprovalPolicy,
    sandboxMode: config.settings.defaultSandboxMode,
    skipGitRepoCheck: config.settings.allowNonGitCodexRuns || !git,
    networkAccessEnabled: false,
    webSearchMode: "disabled"
  };
};

const ticketDraftSchemaJson = {
  type: "object",
  additionalProperties: false,
  required: [
    "title",
    "priority",
    "labels",
    "context",
    "requirements",
    "acceptanceCriteria",
    "clarificationQuestions",
    "implementationNotes"
  ],
  properties: {
    title: { type: "string" },
    priority: { type: "string", enum: ["low", "medium", "high", "urgent"] },
    labels: { type: "array", items: { type: "string" } },
    context: { type: "string" },
    requirements: { type: "array", items: { type: "string" } },
    acceptanceCriteria: { type: "array", items: { type: "string" } },
    clarificationQuestions: { type: "array", items: { type: "string" } },
    implementationNotes: { type: "array", items: { type: "string" } }
  }
} as const;

const parseJsonResponse = (value: string): unknown => {
  try {
    return JSON.parse(value);
  } catch {
    const first = value.indexOf("{");
    const last = value.lastIndexOf("}");
    if (first >= 0 && last > first) {
      return JSON.parse(value.slice(first, last + 1));
    }
    throw new Error("Codex did not return valid JSON.");
  }
};

export const getCodexStatus = async (): Promise<CodexStatus> => {
  let cliAvailable = false;
  let cliVersion: string | null = null;
  try {
    const { stdout } = await execFileAsync("codex", ["--version"], { timeout: 5000 });
    cliAvailable = true;
    cliVersion = stdout.trim();
  } catch {
    cliAvailable = false;
  }

  let authenticated: boolean | null = null;
  const hasApiKey = Boolean(process.env.OPENAI_API_KEY || process.env.CODEX_API_KEY);
  try {
    await readFile(path.join(os.homedir(), ".codex", "auth.json"), "utf8");
    authenticated = true;
  } catch {
    authenticated = hasApiKey ? true : false;
  }

  return {
    sdkAvailable: true,
    cliAvailable,
    cliVersion,
    authenticated,
    message: cliAvailable
      ? authenticated === true
        ? "Codex is available."
        : "Codex CLI is available, but no Codex auth file or API key was found."
      : "Codex CLI was not found on PATH."
  };
};

export const createTicketDraft = async ({ projectPath, idea }: CreateDraftInput): Promise<TicketDraft> => {
  await logInfo("codex:draft", "starting ticket draft", { projectPath, ideaLength: idea.length });
  const status = await getCodexStatus();
  if (!status.cliAvailable) {
    await logWarn("codex:draft", "codex cli unavailable", status);
    throw new Error("Codex CLI was not found on PATH. Install or expose Codex before drafting tickets.");
  }
  if (status.authenticated === false) {
    await logWarn("codex:draft", "codex auth unavailable", status);
    throw new Error("Codex is not authenticated. Run `codex login` in your terminal, then try drafting again.");
  }

  const config = await readProjectConfig(projectPath);
  const codex = createCodex();
  const thread = codex.startThread(await threadOptionsForProject(projectPath));
  const abortController = new AbortController();
  const timeout = setTimeout(() => abortController.abort(), DRAFT_TIMEOUT_MS);
  timeout.unref?.();
  const prompt = `You are helping create a local software implementation ticket for Relay.

The user will provide a rough idea. Convert it into a clear, actionable ticket for a coding agent and human developer.

Return only data matching the requested schema. Do not implement the task.

Project path: ${projectPath}
Project name: ${config.name}
Current board columns: ${config.columns.map((column) => column.name).join(", ")}

User idea:
${idea}`;

  try {
    const turn = await thread.run(prompt, { outputSchema: ticketDraftSchemaJson, signal: abortController.signal });
    const parsed = ticketDraftSchema.parse(parseJsonResponse(turn.finalResponse)) as TicketDraft;
    await logInfo("codex:draft", "ticket draft completed", { projectPath, title: parsed.title });
    return parsed;
  } catch (error) {
    await logError("codex:draft", abortController.signal.aborted ? "ticket draft timed out" : "ticket draft failed", error);
    if (abortController.signal.aborted) {
      throw new Error("Codex ticket drafting timed out after 90 seconds. You can save a manual ticket and try Codex again later.");
    }
    throw error;
  } finally {
    clearTimeout(timeout);
  }
};

const writeRunLog = async (
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Promise<void> => {
  const filePath = path.join(runsPath(projectPath), ticketId, `${runId}.jsonl`);
  await mkdir(path.dirname(filePath), { recursive: true });
  const { type, timestamp, ...payload } = event;
  await appendFile(
    filePath,
    `${JSON.stringify({
      schemaVersion: 1,
      timestamp,
      ticketId,
      runId,
      threadId,
      type,
      payload
    })}\n`,
    "utf8"
  );
};

